# @记
# 需求：修改任意功能代码，保留历史版本；支持整体替换和局部替换两种模式
# 注意：系统功能也可改，用内核函数保存；局部替换自动缩进对齐
# @毕

import json, traceback
from datetime import datetime

with open(_data_file, encoding="utf-8") as f:
    data = json.load(f)

all_items = list(data["actions"].items())
sys_fns  = [(k, v) for k, v in all_items if k in _SYSTEM_KEYS]
tool_fns = [(k, v) for k, v in all_items if k not in _SYSTEM_KEYS]

print("\n选择要修改的功能：")
print(" ── 系统功能 ──")
for k, v in sys_fns:
    print(f" {k}. {v['name']}")
print(" ── 工具功能 ──")
if not tool_fns:
    print(" （暂无工具功能）")
else:
    for i, (k, v) in enumerate(tool_fns, 1):
        print(f" t{i}. {v['name']}")

choice = input("\n编号（系统功能输数字，工具功能输t+数字）：").strip()

key = None
if choice in _SYSTEM_KEYS:
    key = choice
elif choice.startswith("t"):
    try:
        key = tool_fns[int(choice[1:]) - 1][0]
    except (ValueError, IndexError):
        pass

if not key:
    print("⚠️ 无效编号。"); input("回车继续..."); exit()

name = data["actions"][key]["name"]
if key in _SYSTEM_KEYS:
    print(f"\n⚠️ 你正在修改系统功能「{name}」，请确保代码正确。")

print(f"\n修改「{name}」的方式：")
print(" 1. 整体替换（粘完整新代码）")
print(" 2. 局部替换（按行号替换）")

mode = input("\n选择（1/2）：").strip()

if mode not in ("1", "2"):
    print("⚠️ 无效选项。"); input("回车继续..."); exit()

# ==================== 整体替换模式 ====================
if mode == "1":
    print(f"\n粘贴新代码，输入 END 结束：")
    lines = []
    while True:
        line = input()
        if line.strip() == "END":
            break
        lines.append(line)
    code = "\n".join(lines)

    if not code.strip():
        print("⚠️ 没有代码。"); input("回车继续...")
    else:
        memo = _parse_memo(code)
        if not memo:
            print("❌ 缺少备忘录（格式：# @记 / # @毕），无法保存。")
            input("回车继续...")
        else:
            _snap()
            old = data["actions"][key]
            hist = old.get("history", [])
            hist.append({
                "time": datetime.now().strftime("%Y-%m-%d %H:%M"),
                "code": old["code"],
                "memo": old.get("memo", {})
            })
            try:
                data["actions"][key] = {
                    "name": name,
                    "code": code,
                    "memo": memo,
                    "desc": memo.get("原始需求", ""),
                    "added": old.get("added", ""),
                    "modified": datetime.now().strftime("%Y-%m-%d %H:%M"),
                    "history": hist[-10:]
                }
                data = _log(data, f"修改「{name}」")
                _atomic_save(data)
                print(f"\n✅ 「{name}」已更新。")
            except Exception as e:
                print(f"❌ 出错：{e}\n{traceback.format_exc()}")
            input("\n回车继续...")

# ==================== 局部替换模式 ====================
else:
    old_code = data["actions"][key]["code"]
    lines = old_code.splitlines()
    total = len(lines)

    print(f"\n「{name}」共 {total} 行")

    # 显示结构信息
    print("主要结构：")
    for i, line in enumerate(lines):
        if line.strip().startswith(("def ", "class ", "# @记", "# @毕")):
            print(f" · {line.strip()[:50]} 第{i+1}行")

    print()
    try:
        start_line = int(input("起始行号：").strip())
        end_line = int(input("结束行号：").strip())
    except ValueError:
        print("❌ 无效行号。"); input("回车继续..."); exit()

    if start_line < 1 or end_line > total or start_line > end_line:
        print(f"❌ 行号范围无效（有效范围：1-{total}）。"); input("回车继续..."); exit()

    print(f"\n===== 待替换 {start_line}-{end_line} =====")
    for i in range(start_line - 1, end_line):
        print(f"{i+1:03d}: {lines[i]}")
    print("=" * 35)

    print("\n粘贴新内容 (END结束)：")
    new_lines = []
    while True:
        l = input()
        if l.strip() == "END":
            break
        new_lines.append(l)

    if not new_lines:
        print("⚠️ 没有输入。"); input("回车继续..."); exit()

    # 相对缩进算法
    user_indent = 0
    for l in new_lines:
        if l.strip():
            user_indent = len(l) - len(l.lstrip())
            break

    target_indent = len(lines[start_line - 1]) - len(lines[start_line - 1].lstrip())
    offset = target_indent - user_indent

    adj_new = []
    for l in new_lines:
        if not l.strip():
            adj_new.append("")
        else:
            if offset >= 0:
                adj_new.append(" " * offset + l)
            else:
                shift = abs(offset)
                adj_new.append(l[shift:] if l.startswith(" " * shift) else l.lstrip())

    new_code = "\n".join(lines[:start_line - 1] + adj_new + lines[end_line:])

    try:
        compile(new_code, "<string>", "exec")
    except Exception as e:
        print(f"❌ 语法错误：{e}"); input("回车继续..."); exit()

    # 解析备忘录（从新代码或保留旧备忘录）
    memo = _parse_memo(new_code)
    if not memo:
        old_memo = data["actions"][key].get("memo", {})
        memo = old_memo if old_memo else {}
        print("⚠️ 新代码未含备忘录，保留原备忘录")

    print("\n===== 预览新代码（前10行） =====")
    for i, l in enumerate(adj_new[:10]):
        print(f"{start_line+i:03d}: {l}")
    print("=" * 35)

    if input(f"\n确认写入「{name}」？(y/n): ").strip().lower() == "y":
        _snap()
        old = data["actions"][key]
        hist = old.get("history", [])
        hist.append({
            "time": datetime.now().strftime("%Y-%m-%d %H:%M"),
            "code": old["code"],
            "memo": old.get("memo", {})
        })
        data["actions"][key] = {
            "name": name,
            "code": new_code,
            "memo": memo,
            "desc": memo.get("原始需求", ""),
            "added": old.get("added", ""),
            "modified": datetime.now().strftime("%Y-%m-%d %H:%M"),
            "history": hist[-10:]
        }
        data = _log(data, f"局部编辑「{name}」{start_line}-{end_line}行")
        _atomic_save(data)
        print("✅ 已更新")
    else:
        print("已取消")

    input("回车继续...")

