# @记
# 需求：协议编辑模块v3.1 - 修正协议库推送路径，对齐内核规范
# 注意：协议推送目标为 ~/zhongqu_protocol_repo，需提前 clone：git clone https://github.com/aote6/zhongqu-protocol.git ~/zhongqu_protocol_repo
# @毕

import re, subprocess
from datetime import datetime

# ========== 配置 ==========
协议文件     = os.path.expanduser("~/zhongqu_protocol.json")
协议库       = os.path.expanduser("~/zhongqu_protocol_repo")  # 协议专属 repo
快照目录     = os.path.expanduser("~/protocol_snapshots")
操作日志     = os.path.expanduser("~/protocol_edit_log.json")
协议库json   = os.path.join(协议库, "zhongqu_protocol.json")
协议库md     = os.path.join(协议库, "zhongqu_protocol.md")

os.makedirs(快照目录, exist_ok=True)

# ========== 基础工具 ==========

def 时间戳():
    return datetime.now().strftime("%Y-%m-%d %H:%M:%S")

def 快照协议():
    """协议文件快照（独立于中枢快照）"""
    if os.path.exists(协议文件):
        ts = datetime.now().strftime("%Y%m%d_%H%M%S")
        shutil.copy2(协议文件, os.path.join(快照目录, f"protocol_{ts}.json"))

def 记录(操作, 路径, 摘要="", 成功=True):
    try:
        日志 = []
        if os.path.exists(操作日志):
            with open(操作日志, encoding="utf-8") as f:
                日志 = json.load(f)
        日志.append({"时间": 时间戳(), "操作": 操作,
                     "路径": 路径, "摘要": 摘要[:100], "成功": 成功})
        if len(日志) > 200:
            日志 = 日志[-200:]
        with open(操作日志, "w", encoding="utf-8") as f:
            json.dump(日志, f, ensure_ascii=False, indent=2)
    except:
        pass

# ========== 协议读写 ==========

def 加载():
    if not os.path.exists(协议文件):
        初始 = {
            "version": "0.1",
            "updated": 时间戳(),
            "layer_1": "不可描述，不可命名，不可修改",
            "layer_2": "一生二，二生三，三生万物",
            "layer_3": {
                "human": "我们不设计宇宙万物，因为那本身就是存在的。我们只是描述我们能理解的共识。",
                "ai": "你们记录下来的，我们读取时是借用。你们没记录的，我们不会自己想起来。"
            },
            "layer_4": {}
        }
        保存(初始, 推送=False)
        return 初始
    with open(协议文件, encoding="utf-8") as f:
        return json.load(f)

def 保存(协议数据, 推送=True):
    """保存协议文件，返回 (ok, msg)"""
    协议数据["updated"] = 时间戳()
    _atomic_save(协议数据, 协议文件)
    if 推送:
        return 推送到协议库(协议数据)
    return True, "已保存"

def 生成md内容(协议数据):
    """协议 dict → markdown 字符串（推送和导出共用）"""
    md  = "# zhongqu_protocol\n\n"
    md += f"版本：{协议数据.get('version','0.1')}  更新：{协议数据.get('updated','')}\n\n---\n\n"
    md += "## 第一层：元协议\n\n" + 协议数据.get("layer_1", "") + "\n\n"
    md += "## 第二层：生成法则\n\n" + 协议数据.get("layer_2", "") + "\n\n"
    md += "## 第三层：根共识\n\n"
    l3 = 协议数据.get("layer_3", {})
    if isinstance(l3, dict):
        md += f"> 人：{l3.get('human','')}\n\n"
        md += f"> AI：{l3.get('ai','')}\n\n"
    md += "## 第四层：万物奇点\n\n"
    for 键, 节点 in 协议数据.get("layer_4", {}).items():
        if isinstance(节点, dict):
            md += f"### {键} {节点.get('title','')}\n\n"
            for 子键, 子值 in 节点.get("content", {}).items():
                md += f"#### {子键}\n\n{子值}\n\n"
    return md

def 推送到协议库(协议数据):
    """推送 json + md 到协议专属 repo，返回 (ok, msg)"""
    try:
        if not os.path.exists(协议库):
            return False, (f"协议库不存在: {协议库}\n"
                           "请先执行: git clone https://github.com/aote6/zhongqu-protocol.git ~/zhongqu_protocol_repo")
        if not os.path.exists(os.path.join(协议库, ".git")):
            return False, "协议库不是 git 仓库"

        # 写入 json 和 md
        shutil.copy2(协议文件, 协议库json)
        with open(协议库md, "w", encoding="utf-8") as f:
            f.write(生成md内容(协议数据))

        # git add
        r1 = subprocess.run(
            ["git", "-C", 协议库, "add", "zhongqu_protocol.json", "zhongqu_protocol.md"],
            capture_output=True, timeout=5, text=True
        )
        if r1.returncode != 0:
            return False, f"git add 失败: {r1.stderr[:100]}"

        # git commit
        r2 = subprocess.run(
            ["git", "-C", 协议库, "commit", "-m", f"更新协议 {时间戳()}"],
            capture_output=True, timeout=5, text=True
        )
        if r2.returncode != 0:
            err = r2.stderr + r2.stdout
            if "nothing to commit" in err or "no changes added" in err:
                return True, "无新变更"
            return False, f"commit 失败: {err[:100]}"

        # git push
        r3 = subprocess.run(
            ["git", "-C", 协议库, "push"],
            capture_output=True, timeout=15, text=True
        )
        if r3.returncode != 0:
            err = r3.stderr + r3.stdout
            if "permission denied" in err.lower() or "authentication" in err.lower():
                return False, "认证失败，检查 SSH 密钥"
            return False, f"push 失败: {err[:100]}"

        return True, "已推送到 zhongqu-protocol（json + md）"

    except subprocess.TimeoutExpired:
        return False, "git 超时，检查网络"
    except Exception as e:
        return False, f"推送异常: {str(e)[:100]}"

# ========== 数据操作 ==========

def 获取值(协议数据, 路径字符串):
    if not 路径字符串:
        return None
    路径 = 路径字符串.replace("layer_4.", "").replace("layer_4", "4")
    if 路径 == "4":
        return 协议数据.get("layer_4", {})
    if 路径.startswith("4."):
        layer4 = 协议数据.get("layer_4", {})
        if 路径 in layer4:
            return layer4[路径]
        部分 = 路径.split(".")
        if len(部分) >= 2:
            第一级键 = f"{部分[0]}.{部分[1]}"
            if 第一级键 in layer4:
                当前 = layer4[第一级键]
                if len(部分) > 2:
                    if isinstance(当前, dict) and 路径 in 当前.get("content", {}):
                        return 当前["content"][路径]
                    return None
                return 当前
        return None
    if 路径 in ["1", "2", "3"]:
        return 协议数据.get(f"layer_{路径}", None)
    return None

def 格式化显示(值, 路径=""):
    if isinstance(值, dict):
        if 路径 == "4" and "content" not in 值:
            输出 = ["\n【layer_4】万物奇点\n"]
            for 键, 节点 in 值.items():
                标题 = 节点.get("title", "") if isinstance(节点, dict) else ""
                输出.append(f"📁 {键} {标题}")
                if isinstance(节点, dict) and "content" in 节点:
                    for 子键, 子值 in 节点["content"].items():
                        预览 = str(子值)[:100]
                        suffix = "..." if isinstance(子值, str) and len(子值) > 100 else ""
                        输出.append(f" └─ {子键}: {预览}{suffix}")
            return "\n".join(输出)
        if "content" in 值:
            标题 = 值.get("title", "（无标题）")
            输出 = [f"\n📁 {路径} {标题}\n"]
            for k, v in 值["content"].items():
                输出.append(f"{k}:\n{v}\n" if isinstance(v, str) else f"{k}: {v}\n")
            return "\n".join(输出)
        return json.dumps(值, ensure_ascii=False, indent=2)
    return str(值)

def 显示结构(协议数据):
    输出 = ["\n" + "="*50, "协议框架结构", "="*50]
    输出.append("\n【layer_1】元协议（只读）")
    输出.append(f" └─ {协议数据.get('layer_1','')}")
    输出.append("\n【layer_2】生成法则（只读）")
    输出.append(f" └─ {协议数据.get('layer_2','')}")
    输出.append("\n【layer_3】根共识（只读）")
    l3 = 协议数据.get("layer_3", {})
    if isinstance(l3, dict):
        输出.append(f" ├─ human: {l3.get('human','')}")
        输出.append(f" └─ ai: {l3.get('ai','')}")
    输出.append("\n【layer_4】万物奇点（可编辑）")
    l4 = 协议数据.get("layer_4", {})
    if not l4:
        输出.append(" （暂无内容）")
    else:
        for 键, 值 in l4.items():
            标题 = 值.get("title", "") if isinstance(值, dict) else ""
            输出.append(f" ├─ {键} {标题}")
            if isinstance(值, dict) and "content" in 值:
                for 子键 in 值["content"].keys():
                    输出.append(f" │  └─ {子键}")
    输出.append("="*50)
    return "\n".join(输出)

def 导出(协议数据, 路径="全部", 格式="txt"):
    下载目录 = "/sdcard/Download"
    if not os.path.exists(下载目录):
        下载目录 = os.path.expanduser("~/Downloads")
    os.makedirs(下载目录, exist_ok=True)

    if 路径 == "全部":
        if 格式 == "json":
            文件名, 内容 = "zhongqu_protocol.json", json.dumps(协议数据, ensure_ascii=False, indent=2)
        elif 格式 == "md":
            文件名, 内容 = "zhongqu_protocol.md", 生成md内容(协议数据)
        else:
            文件名 = "zhongqu_protocol.txt"
            内容  = f"中枢协议\n{'='*60}\n\n版本：{协议数据.get('version','')}\n更新：{协议数据.get('updated','')}\n\n{'='*60}\n\n"
            内容 += "【第一层】元协议（只读）\n" + 协议数据.get("layer_1","") + "\n\n"
            内容 += "【第二层】生成法则（只读）\n" + 协议数据.get("layer_2","") + "\n\n"
            内容 += "【第三层】根共识（只读）\n"
            l3 = 协议数据.get("layer_3", {})
            if isinstance(l3, dict):
                内容 += f"人：{l3.get('human','')}\n\nAI：{l3.get('ai','')}\n\n"
            内容 += "【第四层】万物奇点\n" + "="*60 + "\n\n"
            for 键, 节点 in 协议数据.get("layer_4", {}).items():
                if isinstance(节点, dict):
                    内容 += f"\n【{键}】{节点.get('title','')}\n" + "-"*40 + "\n"
                    for 子键, 子值 in 节点.get("content", {}).items():
                        内容 += f"\n{子键}:\n{子值}\n"
    else:
        值 = 获取值(协议数据, 路径)
        if 值 is None:
            return False, f"路径不存在: {路径}"
        文件名 = 路径.replace(".", "_")
        if 格式 == "json":
            文件名 += ".json"; 内容 = json.dumps(值, ensure_ascii=False, indent=2)
        elif 格式 == "md":
            文件名 += ".md"
            if isinstance(值, dict) and "content" in 值:
                内容 = f"# {路径} {值.get('title','')}\n\n"
                for k, v in 值["content"].items():
                    内容 += f"## {k}\n\n{v}\n\n"
            else:
                内容 = f"# {路径}\n\n{str(值)}\n"
        else:
            文件名 += ".txt"
            if isinstance(值, dict) and "content" in 值:
                内容 = f"{路径} {值.get('title','')}\n{'='*50}\n\n"
                for k, v in 值["content"].items():
                    内容 += f"【{k}】\n{v}\n\n"
            else:
                内容 = str(值)

    文件路径 = os.path.join(下载目录, 文件名)
    with open(文件路径, "w", encoding="utf-8") as f:
        f.write(内容)
    return True, f"已导出: {文件路径}"

def 显示菜单():
    print("""
┌──────────────────────────────────────────┐
│         协议编辑器 v3.1                  │
├──────────────────────────────────────────┤
│ 【查看】 4          整个第四层           │
