└──────────────────────────────────────────┘
多行内容粘贴完毕后单独一行输入 END 回车。
""")

# ========== 主程序 ==========
def 主程序():
    协议数据 = 加载()
    自动推送 = False  # 默认关闭，手动【推送】更安全

    库已连接 = os.path.exists(os.path.join(协议库, ".git"))

    print("\n" + "="*50)
    print(" 📜 协议编辑器 v3.1")
    print(f" 协议库：{协议库}")
    print(f" 状态：{'✅ 已连接' if 库已连接 else '❌ 未找到，推送不可用（需先 clone）'}")
    print(f" 自动推送：{'开' if 自动推送 else '关'}")
    print("="*50)
    print("输入「帮助」查看菜单，「退出」返回中枢\n")

    while True:
        print("\n命令：", end="", flush=True)
        行们 = []
        while True:
            try:
                行 = input()
                if 行.strip() == "END":
                    break
                行们.append(行)
                if len(行们) == 1 and not 行们[0].strip().startswith("【"):
                    break
            except EOFError:
                break

        输入 = "\n".join(行们).strip()
        if not 输入:
            continue

        第一行 = 输入.split("\n")[0].strip()
        cmd_match = re.match(r"【(.+?)】\s*(.+?)(?:\s+(.+))?$", 第一行)
        if not cmd_match:
            部分 = 第一行.split(maxsplit=2)
            操作 = 部分[0]
            参数1 = 部分[1] if len(部分) > 1 else ""
            参数2 = 部分[2] if len(部分) > 2 else ""
        else:
            操作 = cmd_match.group(1)
            参数1 = cmd_match.group(2)
            参数2 = cmd_match.group(3) or ""

        if 操作 in ["退出", "exit", "q"]:
            print("👋 退出协议编辑器"); break

        elif 操作 in ["帮助", "help", "?"]:
            显示菜单()

        elif 操作 == "结构":
            print(显示结构(协议数据))

        elif 操作 == "日志":
            if os.path.exists(操作日志):
                with open(操作日志, encoding="utf-8") as f:
                    日志 = json.load(f)
                print("\n最近20条：")
                for 项 in 日志[-20:]:
                    状态 = "✅" if 项.get("成功") else "❌"
                    print(f" {状态} {项['时间']} [{项['操作']}] {项['路径']} {项['摘要']}")
            else:
                print("暂无日志")

        elif 操作 == "自动推送":
            自动推送 = 参数1 in ["开", "on", "true"]
            print(f"✅ 自动推送已{'开启' if 自动推送 else '关闭'}")

        elif 操作 == "查看":
            if not 参数1:
                print("❌ 请指定路径，如: 【查看】4"); continue
            if 参数1 == "结构":
                print(显示结构(协议数据))
            else:
                值 = 获取值(协议数据, 参数1)
                if 值 is None:
                    print(f"❌ 路径不存在: {参数1}")
                else:
                    print("\n" + 格式化显示(值, 参数1))

        elif 操作 == "添加":
            if not 参数1:
                print("❌ 格式: 【添加】4 或 【添加】4.1"); continue
            标题 = input("节点标题（回车跳过）：").strip()
            print("节点内容（输入END结束，回车跳过）：")
            内容行 = []
            while True:
