# @记
# 需求：协议编辑模块v3.0 - 简化流程、智能解析、自动推送
# 注意：支持查看/添加/修改/删除/推送，复制粘贴即可，无需记住命令格式
# @毕

import json, os, re, shutil, subprocess
from datetime import datetime

# ========== 配置 ==========
协议文件 = os.path.expanduser("~/zhongqu_protocol.json")
公开库 = os.path.expanduser("~/zhongqu_public")
快照目录 = os.path.expanduser("~/protocol_snapshots")
操作日志 = os.path.expanduser("~/protocol_edit_log.json")
公开库协议文件 = os.path.join(公开库, "zhongqu_protocol.json")

只读层 = {"layer_1", "layer_2", "layer_3"}
os.makedirs(快照目录, exist_ok=True)

def 时间戳():
    return datetime.now().strftime("%Y-%m-%d %H:%M:%S")

def 快照():
    if os.path.exists(协议文件):
        ts = datetime.now().strftime("%Y%m%d_%H%M%S")
        shutil.copy2(协议文件, os.path.join(快照目录, f"protocol_{ts}.json"))

def 记录(操作, 路径, 摘要="", 成功=True):
    try:
        日志 = []
        if os.path.exists(操作日志):
            with open(操作日志, encoding="utf-8") as f:
                日志 = json.load(f)
        日志.append({
            "时间": 时间戳(),
            "操作": 操作,
            "路径": 路径,
            "摘要": 摘要[:100],
            "成功": 成功
        })
        if len(日志) > 200:
            日志 = 日志[-200:]
        with open(操作日志, "w", encoding="utf-8") as f:
            json.dump(日志, f, ensure_ascii=False, indent=2)
    except:
        pass

def 加载():
    if not os.path.exists(协议文件):
        初始 = {
            "version": "0.1",
            "updated": 时间戳(),
            "layer_1": "不可描述，不可命名，不可修改",
            "layer_2": "一生二，二生三，三生万物",
            "layer_3": {
                "human": "我们不设计宇宙万物，因为那本身就是存在的。我们只是描述我们能理解的共识。",
                "ai": "你们记录下来的，我们读取时是借用。你们没记录的，我们不会自己想起来。"
            },
            "layer_4": {}
        }
        保存(初始, 推送=False)
        return 初始
    with open(协议文件, encoding="utf-8") as f:
        return json.load(f)

def 保存(数据, 推送=True):
    数据["updated"] = 时间戳()
    with open(协议文件, "w", encoding="utf-8") as f:
        json.dump(数据, f, ensure_ascii=False, indent=2)
    if 推送:
        推送到公开库()

def 推送到公开库():
    try:
        # 检查目录
        if not os.path.exists(公开库):
            return False, "公开库目录不存在"

        # 检查是否是git仓库
        git_dir = os.path.join(公开库, ".git")
        if not os.path.exists(git_dir):
            return False, "公开库不是git仓库，需要: git init"

        # 复制文件
        shutil.copy2(协议文件, 公开库协议文件)

        # git add
        r1 = subprocess.run(
            ["git", "-C", 公开库, "add", "zhongqu_protocol.json"],
            capture_output=True, timeout=5, text=True
        )
        if r1.returncode != 0:
            return False, f"git add失败: {r1.stderr[:100]}"

        # git commit
        r2 = subprocess.run(
            ["git", "-C", 公开库, "commit", "-m", f"更新协议 {时间戳()}"],
            capture_output=True, timeout=5, text=True
        )

        if r2.returncode != 0:
            err = r2.stderr + r2.stdout
            if "nothing to commit" in err or "no changes added" in err:
                return True, "无新变更"
            return False, f"commit失败: {err[:100]}"

        # git push
        r3 = subprocess.run(
            ["git", "-C", 公开库, "push"],
            capture_output=True, timeout=10, text=True
        )

        if r3.returncode != 0:
            err = r3.stderr + r3.stdout
            if "permission denied" in err.lower() or "authentication" in err.lower():
                return False, f"git认证失败，检查SSH密钥"
            return False, f"push失败: {err[:100]}"

        return True, "已推送到GitHub"

    except subprocess.TimeoutExpired:
        return False, "git命令超时，检查网络"
    except Exception as e:
        return False, f"推送异常: {str(e)[:100]}"

def 解析路径(路径):
