    # 查看整个layer_4
    if 路径 == "4":
        return 数据.get("layer_4", {})

    # 查看layer_4下的具体节点
    if 路径.startswith("4.") or 路径 == "4":
        layer4 = 数据.get("layer_4", {})

        # 尝试直接找这个键（如4.1, 4.1.1）
        if 路径 in layer4:
            return layer4[路径]

        # 如果直接找不到，试试递进查找（4.1.1 -> 找4.1的content中的4.1.1）
        部分 = 路径.split(".")
        if len(部分) >= 2:
            # 先找第一级（如4.1）
            第一级键 = f"{部分[0]}.{部分[1]}"
            if 第一级键 in layer4:
                当前 = layer4[第一级键]
                # 如果还有更深层的路径
                if len(部分) > 2:
                    if isinstance(当前, dict) and "content" in 当前:
                        # 在content中直接用完整的路径找
                        if 路径 in 当前["content"]:
                            return 当前["content"][路径]
                    return None
                return 当前

        return None

    # 其他层（1-3）
    if 路径 in ["1", "2", "3"]:
        return 数据.get(f"layer_{路径}", None)

    return None

def 设置值(数据, 路径列表, 值, 新增=False):
