    当前 = 数据["layer_4"]

    # 逐层导航，自动创建缺失的节点
    for i, 段 in enumerate(路径列表[1:-1], 1):
        if 段 not in 当前:
            if not 新增:
                return False, f"路径不存在: {'.'.join(路径列表[:i+1])}"
            # 自动创建中间节点
