        当前 = 当前[段]
        if "content" in 当前:
            当前 = 当前["content"]

    # 设置最后一层
    最后 = 路径列表[-1]
    if 最后 not in 当前 and not 新增:
        return False, f"路径不存在: {'.'.join(路径列表)}"

    当前[最后] = 值
    return True, "成功"

def 删除值(数据, 路径列表):
