            return False, f"路径不存在"
        当前 = 当前[段]
        if "content" in 当前:
            当前 = 当前["content"]

    最后 = 路径列表[-1]
    if 最后 in 当前:
        del 当前[最后]
        return True, f"已删除 {'.'.join(路径列表)}"

    return False, f"节点不存在"

def 格式化显示(值, 路径=""):
