            if isinstance(值, dict) and "content" in 值:
                标题 = 值.get("title", "")
                内容 = f"# {路径} {标题}\n\n"
                for k, v in 值["content"].items():
                    内容 += f"## {k}\n\n{v}\n\n"
            else:
                内容 = f"# {路径}\n\n{str(值)}\n"
        else:  # txt
            文件名 = f"{文件名}.txt"
            if isinstance(值, dict) and "content" in 值:
                标题 = 值.get("title", "")
                内容 = f"{路径} {标题}\n{'='*50}\n\n"
                for k, v in 值["content"].items():
                    内容 += f"【{k}】\n{v}\n\n"
            else:
                内容 = str(值)

    文件路径 = os.path.join(下载目录, 文件名)
    with open(文件路径, "w", encoding="utf-8") as f:
        f.write(内容)

    return True, f"已导出: {文件名}"

def 显示菜单():
    print(""" ┌─────────────────────────────────────────────┐ │ 协议编辑器 v3.0 - 交互式编辑 │ ├─────────────────────────────────────────────┤ │ 【查看】 4 显示整个第四层 │ │ 【查看】 4.1 显示单个节点 │ │ 【查看】 结构 显示框架大纲 │ │ │ │ 【添加】 4 新增一个一级节点 │ │ │ │ 【修改】 4.1 替换某个节点内容 │ │ 【修改】 4.1 标题 修改节点标题 │ │ │ │ 【删除】 4.1 删除某个节点 │ │ │ │ 【导出】 4.1 导出为txt/md/json │ │ 【导出】 全部 导出所有为zip文件 │ │ │ │ 【推送】 推送到公开库 │ │ 【日志】 查看操作日志 │ │ 【帮助】 显示本菜单 │ │ 退出 │ └─────────────────────────────────────────────┘ 说明： · 复制粘贴：输入多行时，粘贴完毕输入 END 回车 · 智能检测：模块自动判断操作类型，处理缩进和编号 · 自动推送：修改后自动推送公开库（可选关闭） · 导出格式：txt(文本) md(markdown) json(原始)，默认txt """)

# ========== 主程序 ==========
def 主程序():
    数据 = 加载()
    自动推送 = True

    print("\n" + "=" * 50)
    print(" 📜 协议编辑器 v3.0")
    print("=" * 50)
    print("输入「帮助」查看菜单，「退出」返回中枢\n")

    while True:
        print("\n命令：", end="", flush=True)

        # 读取多行输入
        行们 = []
        while True:
            try:
                行 = input()
                if 行.strip() == "END":
                    break
                行们.append(行)
                if len(行们) == 1 and not 行们[0].strip().startswith("【"):
                    # 单行命令直接执行
                    break
            except EOFError:
                break

        输入 = "\n".join(行们).strip()
        if not 输入:
            continue

        # 解析命令
        第一行 = 输入.split("\n")[0].strip()
        剩余 = "\n".join(输入.split("\n")[1:]).strip()

        # 匹配命令格式
        cmd_match = re.match(r"【(.+?)】\s*(.+?)(?:\s+(.+))?$", 第一行)
        if not cmd_match:
            # 尝试不带括号的格式
            部分 = 第一行.split(maxsplit=2)
            操作 = 部分[0]
            参数1 = 部分[1] if len(部分) > 1 else ""
            参数2 = 部分[2] if len(部分) > 2 else ""
        else:
            操作 = cmd_match.group(1)
            参数1 = cmd_match.group(2)
            参数2 = cmd_match.group(3) or ""

        # ========== 命令处理 ==========

        if 操作 in ["退出", "exit", "q"]:
            print("👋 退出协议编辑器"); break

        elif 操作 in ["帮助", "help", "?"]:
            显示菜单()

        elif 操作 == "结构":
            print(显示结构(数据))

        elif 操作 == "日志":
            if os.path.exists(操作日志):
                with open(操作日志, encoding="utf-8") as f:
                    日志 = json.load(f)
                print("\n最近20条操作：")
                for 项 in 日志[-20:]:
                    print(f" {项['时间']} [{项['操作']}] {项['路径']} {项['摘要']}")
            else:
                print("暂无日志")

        elif 操作 == "查看":
            if not 参数1:
                print("❌ 请指定路径，如: 【查看】4 或 【查看】4.1")
                continue

            if 参数1 == "结构":
                print(显示结构(数据))
            else:
                值 = 获取值(数据, 参数1)
                if 值 is None:
                    print(f"❌ 路径不存在: {参数1}")
                else:
                    print("\n" + 格式化显示(值, 参数1))

        elif 操作 == "添加":
            if not 参数1:
                print("❌ 格式: 【添加】4 (添加一级节点)")
                print(" 【添加】4.1 (在4.1下添加子节点)")
                continue

            # 询问标题和内容
            标题 = input("节点标题（可选）：").strip()
            内容提示 = input("节点内容（可选，输入END结束，或回车跳过）：\n").strip()

            if 内容提示 != "END":
                内容行 = [内容提示] if 内容提示 else []
                while True:
                    行 = input()
                    if 行.strip() == "END":
                        break
                    内容行.append(行)
                内容文本 = "\n".join(内容行).strip()
            else:
                内容文本 = ""

            # 生成新编号 - 支持多层级自动递增
            部分 = 参数1.split(".")
            layer4 = 数据.get("layer_4", {})

            if len(部分) == 1 and 部分[0] == "4":
                # 在layer_4下添加一级节点（4.1, 4.2, ...）
                最大 = 0
                for 键 in layer4.keys():
                    try:
                        if "." in 键:
                            num = int(键.split(".")[1])
                            最大 = max(最大, num)
                    except:
                        pass
                新编号 = f"4.{最大 + 1}"
                节点 = {"title": 标题, "content": {}}
                if 内容文本:
                    节点["content"][f"{新编号}.1"] = 内容文本
                快照()
                layer4[新编号] = 节点
                保存(数据, 推送=自动推送)
                记录("添加", 新编号, 标题)
                print(f"\n✅ 已添加一级节点: {新编号}")
                if 标题:
                    print(f" 标题: {标题}")
                if 内容文本:
                    print(f" 内容: {内容文本[:100]}...")

            elif len(部分) >= 2:
                # 在某个节点下添加子节点（如在4.1下添加4.1.2, 4.1.3...）
                第一级键 = f"4.{部分[1]}"
                if 第一级键 not in layer4:
                    print(f"❌ 父节点不存在: {第一级键}")
                    continue

                父节点 = layer4[第一级键]
                if not isinstance(父节点, dict):
                    print(f"❌ {第一级键} 不是节点对象")
                    continue

                if "content" not in 父节点:
                    父节点["content"] = {}

                # 查找最大的子编号
                最大子编号 = 1
                当前内容 = 父节点["content"]
                前缀 = 参数1.rstrip(".")
                for 键 in 当前内容.keys():
                    if 键.startswith(前缀 + "."):
                        try:
                            num = int(键.split(".")[-1])
                            最大子编号 = max(最大子编号, num)
                        except:
                            pass

                新编号 = f"{前缀}.{最大子编号 + 1}"
                当前内容[新编号] = 内容文本 if 内容文本 else 标题

                快照()
                保存(数据, 推送=自动推送)
                记录("添加", 新编号, 标题 or 内容文本[:50])
                print(f"\n✅ 已添加子节点: {新编号}")
                if 标题:
                    print(f" 标题: {标题}")
                if 内容文本:
                    print(f" 内容: {内容文本[:100]}...")
            else:
                print("❌ 无效的添加路径")

        elif 操作 == "修改":
            if not 参数1:
                print("❌ 请指定路径，如: 【修改】4.1")
                continue

            旧值 = 获取值(数据, 参数1)

            if 旧值 is None:
                print(f"❌ 路径不存在: {参数1}")
                continue

            # 判断修改类型
            if 参数2 == "标题":
                if not isinstance(旧值, dict):
                    print("❌ 只有节点对象才能改标题")
                    continue
                新标题 = input("新标题：").strip()
                旧值["title"] = 新标题
                快照()
                保存(数据, 推送=自动推送)
                记录("修改", 参数1, f"改标题: {新标题}")
                print(f"✅ 标题已更新")
            else:
                # 替换整个内容
                print(f"\n原内容:\n{格式化显示(旧值, 参数1)}")
                print("\n粘贴新内容（输入END结束）：")

                新行 = []
                while True:
                    行 = input()
                    if 行.strip() == "END":
                        break
                    新行.append(行)
                新值 = "\n".join(新行).strip()

                if not 新值:
                    print("已取消")
                    continue

                print(f"\n新内容:\n{新值[:200]}...")
                if input("确认修改？(y/n): ").strip().lower() != "y":
                    print("已取消")
                    continue

                # 直接在原位置修改
                成功 = False
                if 参数1 == "4":
                    print("❌ 不能替换整个第四层")
                elif 参数1 in 数据.get("layer_4", {}):
                    # 直接替换layer_4下的节点
                    数据["layer_4"][参数1] = 新值
                    成功 = True
                else:
                    # 在某个节点的content里找
                    for 第一级 in 数据.get("layer_4", {}).keys():
                        节点 = 数据["layer_4"][第一级]
                        if isinstance(节点, dict) and "content" in 节点:
                            if 参数1 in 节点["content"]:
                                节点["content"][参数1] = 新值
                                成功 = True
                                break

                if 成功:
                    快照()
                    保存(数据, 推送=自动推送)
                    记录("修改", 参数1, 新值[:50])
                    print(f"✅ 已更新")
                else:
                    print(f"❌ 路径设置失败")

        elif 操作 == "删除":
            if not 参数1:
                print("❌ 请指定路径，如: 【删除】4.1")
                continue

            值 = 获取值(数据, 参数1)

            if 值 is None:
                print(f"❌ 路径不存在: {参数1}")
                continue

            预览 = 格式化显示(值, 参数1)[:150]
            print(f"\n将删除:\n{预览}...")

            if input("\n确认删除？(y/n): ").strip().lower() != "y":
                print("已取消")
                continue

            # 直接删除
            成功 = False
            if 参数1 == "4":
                print("❌ 不能删除整个第四层")
            elif 参数1 in 数据.get("layer_4", {}):
                del 数据["layer_4"][参数1]
                成功 = True
            else:
                # 在某个节点的content里找
                for 第一级 in 数据.get("layer_4", {}).keys():
                    节点 = 数据["layer_4"][第一级]
                    if isinstance(节点, dict) and "content" in 节点:
                        if 参数1 in 节点["content"]:
                            del 节点["content"][参数1]
                            成功 = True
                            break

            if 成功:
                快照()
                保存(数据, 推送=自动推送)
                记录("删除", 参数1, "已删除")
                print(f"✅ 已删除 {参数1}")
            else:
                print(f"❌ 删除失败")

        elif 操作 == "推送":
            print("正在推送到公开库...")
            成功, 消息 = 推送到公开库()
            if 成功:
                print(f"✅ {消息}")
                记录("推送", "公开库", 消息)
            else:
                print(f"❌ {消息}")
                记录("推送", "公开库", 消息, 成功=False)

        elif 操作 == "导出":
            if not 参数1:
                print("❌ 请指定: 【导出】全部 或 【导出】4.1")
                continue

            # 选择格式
            格式选项 = input("导出格式(txt/md/json，默认txt): ").strip().lower()
            if 格式选项 not in ["txt", "md", "json"]:
                格式选项 = "txt"

            成功, 消息 = 导出(数据, 参数1, 格式选项)
            if 成功:
                print(f"✅ {消息}")
                记录("导出", 参数1, 格式选项)
            else:
                print(f"❌ {消息}")

        else:
            print(f"❌ 未知操作: {操作}")
            print("输入「帮助」查看可用命令")

# ========== 执行 ==========
if __name__ == "__main__":
    try:
        快照()
    except:
        pass
    主程序()
